// Outbound port, named in application terms
public interface StudentRepository {
    Optional<Student> findById(Long id);
    void save(Student student);
}

// Framework-light application service
public final class EnrollStudent {
    private final StudentRepository students;

    public EnrollStudent(StudentRepository students) {
        this.students = students;
    }

    public void execute(Long studentId, Long classId) {
        Student student = students.findById(studentId)
            .orElseThrow(() -> new StudentNotFound(studentId));
        student.enrollIn(classId);
        students.save(student);
    }
}

// Outbound adapter
@ApplicationScoped
public class StudentJpaRepository implements StudentRepository {
    @PersistenceContext EntityManager entityManager;

    public Optional<Student> findById(Long id) {
        return Optional.ofNullable(entityManager.find(Student.class, id));
    }
}
